namespace Application.Services.Interface;

/// <summary>
/// Sends SMS messages for calendar reminders and notifications.
/// </summary>
public interface ISmsService
{
    /// <summary>
    /// Sends an SMS message to the specified phone number.
    /// </summary>
    /// <param name="phoneNumber">Destination phone number.</param>
    /// <param name="message">Message body.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    /// <returns>True when the message was accepted for delivery.</returns>
    Task<bool> SendAsync(string phoneNumber, string message, CancellationToken cancellationToken);
}

namespace Application.Option;

/// <summary>
/// Configuration options for SMS delivery.
/// </summary>
public sealed class SmsOption
{
    /// <summary>Gets whether SMS sending is enabled.</summary>
    public bool Enabled { get; init; }

    /// <summary>Gets the SMS provider name (e.g. Mock, Kavenegar).</summary>
    public string Provider { get; init; } = "Mock";
}

using Application.Option;
using Application.Services.Interface;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace Infrastructure.Services;

/// <summary>
/// Logs SMS messages instead of sending them (V1 development provider).
/// </summary>
public class MockSmsService(
    IOptions<SmsOption> options,
    ILogger<MockSmsService> logger) : ISmsService
{
    /// <inheritdoc />
    public Task<bool> SendAsync(string phoneNumber, string message, CancellationToken cancellationToken)
    {
        if (!options.Value.Enabled)
        {
            logger.LogInformation("SMS disabled — skipped send to {PhoneNumber}", phoneNumber);
            return Task.FromResult(false);
        }

        logger.LogInformation(
            "Mock SMS [{Provider}] to {PhoneNumber}: {Message}",
            options.Value.Provider,
            phoneNumber,
            message);

        return Task.FromResult(true);
    }
}

