namespace Application.Features.Query;

/// <summary>Query to list calendars visible to the current user.</summary>
public record CalendarListQuery : IRequest<Result<List<CalendarDto>>>;

using Application.DTOs.Calendar;
using Application.Features.App.Calendar;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles calendar list with auto-create of default personal calendar.</summary>
public class CalendarListQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<CalendarListQuery, Result<List<CalendarDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<CalendarDto>>> Handle(
        CalendarListQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();
            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            var personal = await context.Calendars
                .FirstOrDefaultAsync(
                    x => x.Type == CalendarType.Personal
                         && x.OwnerUserId == userId
                         && x.IsDefault,
                    cancellationToken);

            if (personal is null)
            {
                personal = Calendar.CreateDefaultPersonal(userId);
                await context.Calendars.AddAsync(personal, cancellationToken);
                await context.SaveChangesAsync(cancellationToken);
            }

            var calendars = await context.Calendars
                .AsNoTracking()
                .Where(x =>
                    (x.Type == CalendarType.Personal && x.OwnerUserId == userId)
                    || (x.Type == CalendarType.Unit
                        && x.OrgPositionId.HasValue
                        && positionIds.Contains(x.OrgPositionId.Value))
                    || x.Type == CalendarType.Organization)
                .OrderBy(x => x.Type)
                .ThenBy(x => x.Id)
                .ToListAsync(cancellationToken);

            var dtos = new List<CalendarDto>();
            foreach (var calendar in calendars)
            {
                dtos.Add(await CalendarAccessHelper.ToDtoAsync(
                    calendar, userId, currentUser, positionIds, cancellationToken));
            }

            return Result<List<CalendarDto>>.Success(dtos);
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarList: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

