namespace Application.Features.Command;

/// <summary>Handles calendar creation.</summary>
public class CalendarCreateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<CalendarCreateCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        CalendarCreateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (string.IsNullOrWhiteSpace(model.Title))
                return CalendarErrors.TitleRequired;

            if (model.Title.Trim().Length < 2)
                return CalendarErrors.TitleTooShort;

            if (model.Type == CalendarType.Unit)
            {
                if (!model.OrgPositionId.HasValue)
                    return CalendarErrors.OrgPositionRequired;

                var positionExists = await context.OrgPositions
                    .AsNoTracking()
                    .AnyAsync(x => x.Id == model.OrgPositionId.Value, cancellationToken);

                if (!positionExists)
                    return CalendarErrors.OrgPositionNotFound;
            }

            if (model.Type == CalendarType.Organization && !await currentUser.IsAdmin())
                return CalendarErrors.CreateOrganizationForbidden;

            var entity = new Calendar
            {
                Title = model.Title.Trim(),
                Type = model.Type,
                OwnerUserId = model.Type == CalendarType.Personal ? userId : null,
                OrgPositionId = model.Type == CalendarType.Unit ? model.OrgPositionId : null,
                Color = string.IsNullOrWhiteSpace(model.Color) ? "#2196F3" : model.Color.Trim(),
                IsDefault = false
            };

            await context.Calendars.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"CalendarCreate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

