using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.App.Calendar;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles calendar event creation.</summary>
public class EventCreateCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventCreateCommand, Result<int>>
{
    /// <inheritdoc />
    public async Task<Result<int>> Handle(
        EventCreateCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            var validationError = ValidateEventInput(model);
            if (validationError is not null)
                return validationError;

            var recurrenceError = CalendarAccessHelper.ValidateRecurrence(model.Recurrence);
            if (recurrenceError is not null)
                return recurrenceError;

            var calendar = await context.Calendars
                .FirstOrDefaultAsync(x => x.Id == model.CalendarId, cancellationToken);

            if (calendar is null)
                return CalendarErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanWriteAsync(
                    calendar, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.WriteForbidden;

            var participantIds = model.ParticipantUserIds ?? [];
            if (participantIds.Count > 0)
            {
                var existingCount = await context.AppUsers
                    .AsNoTracking()
                    .CountAsync(x => participantIds.Contains(x.Id), cancellationToken);

                if (existingCount != participantIds.Distinct().Count())
                    return EventErrors.InviteeNotFound;
            }

            if (model.Reminders is not null)
            {
                foreach (var reminder in model.Reminders)
                {
                    if (reminder.OffsetMinutes < 0)
                        return EventErrors.InvalidReminderOffset;
                }
            }

            var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                context,
                participantIds,
                model.StartAt,
                model.EndAt,
                null,
                cancellationToken);

            if (conflictName is not null)
                return EventErrors.Conflict(conflictName);

            var entity = new CalendarEvent
            {
                CalendarId = model.CalendarId,
                CreatedByUserId = userId,
                Title = model.Title.Trim(),
                Description = model.Description,
                Location = model.Location,
                Type = model.Type,
                Status = EventStatus.Confirmed,
                StartAt = model.StartAt,
                EndAt = model.EndAt,
                IsAllDay = model.IsAllDay,
                IsPersonal = model.IsPersonal,
                VisibleOnlyToParticipants = model.VisibleOnlyToParticipants
            };

            foreach (var pid in participantIds.Distinct())
            {
                entity.Participants.Add(new CalendarParticipant
                {
                    UserId = pid,
                    Response = ParticipantResponse.Pending
                });
            }

            if (model.Reminders is not null)
            {
                foreach (var r in model.Reminders)
                {
                    entity.Reminders.Add(new CalendarReminder
                    {
                        OffsetMinutes = r.OffsetMinutes,
                        Channel = r.Channel
                    });
                }
            }

            if (model.Recurrence is not null && model.Recurrence.Type != RecurrenceType.None)
            {
                entity.Recurrence = new CalendarRecurrence
                {
                    Type = model.Recurrence.Type,
                    Interval = model.Recurrence.Interval,
                    WeekDays = RecurrenceExpander.SerializeWeekDays(model.Recurrence.WeekDays),
                    EndDate = model.Recurrence.EndDate,
                    OccurrenceCount = model.Recurrence.OccurrenceCount
                };
            }

            await context.CalendarEvents.AddAsync(entity, cancellationToken);
            await context.SaveChangesAsync(cancellationToken);

            return Result<int>.Success(entity.Id);
        }
        catch (Exception ex)
        {
            Log.Error($"EventCreate: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static Error? ValidateEventInput(EventCreateDto model)
    {
        if (string.IsNullOrWhiteSpace(model.Title))
            return EventErrors.TitleRequired;

        if (model.Title.Trim().Length < 2)
            return EventErrors.TitleTooShort;

        if (model.Description?.Length > 2048)
            return EventErrors.DescriptionTooLong;

        if (model.EndAt <= model.StartAt)
            return EventErrors.InvalidTimeRange;

        if (!Enum.IsDefined(typeof(EventType), model.Type))
            return EventErrors.InvalidType;

        return null;
    }
}

