namespace Application.Features.Command;

/// <summary>Handles calendar event soft-delete.</summary>
public class EventDeleteCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime)
    : IRequestHandler<EventDeleteCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventDeleteCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Recurrence)
                .Include(x => x.Exceptions)
                .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (entity.CreatedByUserId != userId)
            {
                var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                    context, userId, cancellationToken);

                if (!await CalendarAccessHelper.CanWriteAsync(
                        entity.Calendar, userId, currentUser, positionIds, cancellationToken))
                    return EventErrors.DeleteForbidden;
            }

            var hasRecurrence = entity.Recurrence is not null
                                && entity.Recurrence.Type != RecurrenceType.None;

            if (hasRecurrence && request.EditScope.HasValue && request.EditScope != RecurrenceEditScope.All)
            {
                if (!request.OccurrenceDate.HasValue)
                    return EventErrors.OccurrenceDateRequired;

                var occurrence = request.OccurrenceDate.Value;
                var existing = entity.Exceptions
                    .FirstOrDefault(x => x.OccurrenceDate.Date == occurrence.Date);

                if (existing is null)
                {
                    existing = new CalendarEventException
                    {
                        EventId = entity.Id,
                        OccurrenceDate = occurrence
                    };
                    entity.Exceptions.Add(existing);
                }

                existing.IsCancelled = true;
                await context.SaveChangesAsync(cancellationToken);
                return Result<bool>.Success(true);
            }

            entity.IsDeleted = true;
            entity.DeleteDate = dateTime.Now;
            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventDelete: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

