using Application.Data;
using Application.Services;
using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.CalendarSupport;

/// <summary>
/// Sends in-app and SMS notifications for calendar event invitations.
/// </summary>
public static class CalendarInviteNotificationHelper
{
    /// <summary>
    /// Notifies newly invited users via notification center (push/in-app) and SMS.
    /// </summary>
    /// <param name="context">Database context.</param>
    /// <param name="dateTime">Clock service.</param>
    /// <param name="smsService">SMS delivery service.</param>
    /// <param name="eventId">The calendar event id.</param>
    /// <param name="eventTitle">The event title.</param>
    /// <param name="inviterName">The inviter display name.</param>
    /// <param name="inviteeUserIds">User ids that were newly invited.</param>
    /// <param name="cancellationToken">Cancellation token.</param>
    public static async Task NotifyInviteesAsync(
        IApplicationDbContext context,
        IDateTimeService dateTime,
        ISmsService smsService,
        int eventId,
        string eventTitle,
        string inviterName,
        IReadOnlyList<int> inviteeUserIds,
        CancellationToken cancellationToken)
    {
        if (inviteeUserIds.Count == 0)
            return;

        var users = await context.AppUsers
            .AsNoTracking()
            .Where(x => inviteeUserIds.Contains(x.Id))
            .Select(x => new { x.Id, x.PhoneNumber })
            .ToListAsync(cancellationToken);

        foreach (var userId in inviteeUserIds)
        {
            var notification = NotificationCenter.CalendarInvite(
                eventId,
                eventTitle,
                inviterName,
                userId);

            var existing = await context.NotificationCenters
                .Where(x => x.DataId == eventId)
                .Where(x => x.Type == NotificationType.Calendar)
                .Where(x => x.UserId == userId)
                .FirstOrDefaultAsync(cancellationToken);

            if (existing is not null)
            {
                existing.Items.Add(notification.Items.First());
                existing.LastDateTime = dateTime.Now;
            }
            else
            {
                notification.LastDateTime = dateTime.Now;
                context.NotificationCenters.Add(notification);
            }

            var phone = users.FirstOrDefault(x => x.Id == userId)?.PhoneNumber;
            if (!string.IsNullOrWhiteSpace(phone))
            {
                var smsBody =
                    $"دعوت به رویداد «{eventTitle}» از طرف {inviterName}. لطفاً در اپلیکیشن پاسخ دهید.";
                await smsService.SendAsync(phone, smsBody, cancellationToken);
            }
        }
    }
}

using Application.DTOs.Calendar;
using FluentValidation;

namespace Application.Features.Command;

/// <summary>Command to add participants to a calendar event.</summary>
/// <param name="Model">Participant add input.</param>
public record EventAddParticipantsCommand(EventAddParticipantsDto Model) : IRequest<Result<bool>>;

/// <summary>Validates participant add input.</summary>
public class EventAddParticipantsCommandValidator : AbstractValidator<EventAddParticipantsCommand>
{
    public EventAddParticipantsCommandValidator()
    {
        RuleFor(x => x.Model.EventId).GreaterThan(0);
        RuleFor(x => x.Model.UserIds)
            .NotEmpty().WithMessage("حداقل یک کاربر الزامی است");
    }
}

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Application.Services.Interface;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles adding participants to a calendar event (D1).</summary>
public class EventAddParticipantsCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime,
    ISmsService smsService)
    : IRequestHandler<EventAddParticipantsCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventAddParticipantsCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (model.UserIds is null || model.UserIds.Count == 0)
                return EventErrors.AtLeastOneUserRequired;

            var distinctIds = model.UserIds.Distinct().ToList();

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.ParticipantAddForbidden;

            var existingCount = await context.AppUsers
                .AsNoTracking()
                .CountAsync(x => distinctIds.Contains(x.Id), cancellationToken);

            if (existingCount != distinctIds.Count)
                return EventErrors.InviteeNotFound;

            var activeParticipantIds = entity.Participants
                .Where(x => !x.IsDeleted)
                .Select(x => x.UserId)
                .ToHashSet();

            var newIds = distinctIds
                .Where(id => !activeParticipantIds.Contains(id))
                .ToList();

            if (newIds.Count > 0)
            {
                var conflictName = await EventConflictHelper.FindConflictUserNameAsync(
                    context,
                    newIds,
                    entity.StartAt,
                    entity.EndAt,
                    entity.Id,
                    cancellationToken);

                if (conflictName is not null)
                    return EventErrors.Conflict(conflictName);
            }

            var restoredIds = new List<int>();

            foreach (var inviteeId in distinctIds)
            {
                if (activeParticipantIds.Contains(inviteeId))
                    continue;

                var deleted = entity.Participants
                    .FirstOrDefault(x => x.UserId == inviteeId && x.IsDeleted);

                if (deleted is not null)
                {
                    deleted.IsDeleted = false;
                    deleted.DeleteBy = null;
                    deleted.DeleteDate = null;
                    deleted.Response = ParticipantResponse.Pending;
                    restoredIds.Add(inviteeId);
                }
                else
                {
                    entity.Participants.Add(new CalendarParticipant
                    {
                        UserId = inviteeId,
                        Response = ParticipantResponse.Pending
                    });
                    restoredIds.Add(inviteeId);
                }
            }

            await context.SaveChangesAsync(cancellationToken);

            if (restoredIds.Count > 0)
            {
                var inviter = await context.AppUsers
                    .AsNoTracking()
                    .Where(x => x.Id == userId)
                    .Select(x => x.Name)
                    .FirstOrDefaultAsync(cancellationToken) ?? "کاربر";

                await CalendarInviteNotificationHelper.NotifyInviteesAsync(
                    context,
                    dateTime,
                    smsService,
                    entity.Id,
                    entity.Title,
                    inviter,
                    restoredIds,
                    cancellationToken);

                await context.SaveChangesAsync(cancellationToken);
            }

            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventAddParticipants: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

namespace Application.Features.Command;

/// <summary>Command to remove a participant from a calendar event.</summary>
/// <param name="EventId">The event identifier.</param>
/// <param name="UserId">The participant user identifier.</param>
public record EventRemoveParticipantCommand(int EventId, int UserId) : IRequest<Result<bool>>;

using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;
using Domain.Models;

namespace Application.Features.Command;

/// <summary>Handles removing a participant from a calendar event (D2).</summary>
public class EventRemoveParticipantCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser,
    IDateTimeService dateTime)
    : IRequestHandler<EventRemoveParticipantCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventRemoveParticipantCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .Include(x => x.Calendar)
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.ParticipantNotFound;

            var participant = entity.Participants
                .FirstOrDefault(x => x.UserId == request.UserId && !x.IsDeleted);

            if (participant is null)
                return EventErrors.ParticipantNotFound;

            var positionIds = await CalendarAccessHelper.GetUserPositionIdsAsync(
                context, userId, cancellationToken);

            if (!await CalendarAccessHelper.CanEditEventAsync(
                    entity, userId, currentUser, positionIds, cancellationToken))
                return EventErrors.ParticipantRemoveForbidden;

            participant.IsDeleted = true;
            participant.DeleteDate = dateTime.Now;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventRemoveParticipant: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Application.DTOs.Calendar;
using FluentValidation;

namespace Application.Features.Command;

/// <summary>Command for an invitee to respond to a calendar event invitation.</summary>
/// <param name="Model">RSVP input.</param>
public record EventRespondCommand(EventRespondDto Model) : IRequest<Result<bool>>;

/// <summary>Validates RSVP input.</summary>
public class EventRespondCommandValidator : AbstractValidator<EventRespondCommand>
{
    public EventRespondCommandValidator()
    {
        RuleFor(x => x.Model.EventId).GreaterThan(0);
        RuleFor(x => x.Model.Response).NotEmpty();
    }
}

using Application.Errors;
using Application.Services;

namespace Application.Features.Command;

/// <summary>Handles invitee RSVP responses (D3).</summary>
public class EventRespondCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventRespondCommand, Result<bool>>
{
    /// <inheritdoc />
    public async Task<Result<bool>> Handle(
        EventRespondCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            var model = request.Model;
            var userId = currentUser.UserId();

            if (!TryParseResponse(model.Response, out var response))
                return EventErrors.InvalidResponse;

            var entity = await context.CalendarEvents
                .Include(x => x.Participants)
                .FirstOrDefaultAsync(x => x.Id == model.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            var participant = entity.Participants
                .FirstOrDefault(x => x.UserId == userId && !x.IsDeleted);

            if (participant is null)
                return EventErrors.NotInvited;

            participant.Response = response;

            await context.SaveChangesAsync(cancellationToken);
            return Result<bool>.Success(true);
        }
        catch (Exception ex)
        {
            Log.Error($"EventRespond: {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static bool TryParseResponse(string value, out ParticipantResponse response)
    {
        response = default;
        if (string.IsNullOrWhiteSpace(value))
            return false;

        return value.Trim() switch
        {
            "Accepted" => Assign(ParticipantResponse.Accepted, out response),
            "Declined" => Assign(ParticipantResponse.Declined, out response),
            "Maybe" => Assign(ParticipantResponse.Maybe, out response),
            _ => false
        };
    }

    private static bool Assign(ParticipantResponse value, out ParticipantResponse result)
    {
        result = value;
        return true;
    }
}

using Application.DTOs.Calendar;

namespace Application.Features.Query;

/// <summary>Query to list participants for a calendar event.</summary>
/// <param name="EventId">The event identifier.</param>
public record EventParticipantsQuery(int EventId) : IRequest<Result<List<ParticipantDto>>>;

using Application.DTOs.Calendar;
using Application.Errors;
using Application.Features.CalendarSupport;
using Application.Services;

namespace Application.Features.Query;

/// <summary>Handles listing event participants (D4).</summary>
public class EventParticipantsQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUser)
    : IRequestHandler<EventParticipantsQuery, Result<List<ParticipantDto>>>
{
    /// <inheritdoc />
    public async Task<Result<List<ParticipantDto>>> Handle(
        EventParticipantsQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            var userId = currentUser.UserId();

            var entity = await context.CalendarEvents
                .AsNoTracking()
                .Include(x => x.Participants).ThenInclude(x => x.User)
                .FirstOrDefaultAsync(x => x.Id == request.EventId, cancellationToken);

            if (entity is null)
                return EventErrors.NotFound;

            if (!CalendarAccessHelper.CanViewEventParticipants(entity, userId))
                return EventErrors.ParticipantsViewForbidden;

            var dtos = entity.Participants
                .Where(x => !x.IsDeleted)
                .Select(p => new ParticipantDto
                {
                    UserId = p.UserId,
                    FullName = p.User.Name,
                    Response = p.Response
                })
                .ToList();

            return Result<List<ParticipantDto>>.Success(dtos);
        }
        catch (Exception ex)
        {
            Log.Error($"EventParticipants: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

